	this.frame_7 = function() {
		this.stop();
		
		
		var that = this;
		
		var hjbArrays = [];
		var isMove = false;
		
		that.isListenerAndVar;
		
		(function setlisteners() {
		
			if (!that.isListenerAndVar) {
		
				oldX = 0, oldY = 0, pt = 0, cursor = 0;
		
				that.qalam.addEventListener("click", kom);
				that.mimsaha.addEventListener("click", kom1);
				that.somkmc.addEventListener("click", kom2);
				that.qlamv.addEventListener("click", kom3);
		
				that.square.addEventListener("click", toSquare);
				that.circle.addEventListener("click", toCircle);
		
		
		
				that.qalam.addEventListener("mouseover", overBtn);
				that.qalam.addEventListener("mouseout", outBtn);
		
		
		
				that.mimsaha.addEventListener("mouseover", overBtn);
				that.mimsaha.addEventListener("mouseout", outBtn);
		
		
		
				that.somkmc.addEventListener("mouseover", overBtn);
				that.somkmc.addEventListener("mouseout", outBtn);
		
				that.square.addEventListener("mouseover", overBtn);
				that.square.addEventListener("mouseout", outBtn);
		
				that.circle.addEventListener("mouseover", overBtn);
				that.circle.addEventListener("mouseout", outBtn);
		
		
				that.isListenerAndVar = true;
		
		
			}
		
		
		
		
		
		
		})();
		
		function overBtn(ev) {
			ev.currentTarget.bkg.alpha = ev.currentTarget.bkg.alpha == 1 ? 1 : 0.2;
		}
		function outBtn(ev) {
			ev.currentTarget.bkg.alpha = ev.currentTarget.bkg.alpha == 1 ? 1 : 0.6;
		}
		
		that.circle.bkg.alpha = 0.6;
		that.square.bkg.alpha = 0.6;
		that.qalam.bkg.alpha = 1;
		that.mimsaha.bkg.alpha = 0.6;
		that.somkmc.bkg.alpha = 0.6;
		
		
		var sbr = new createjs.Container();
		
		sbr.x = -80; //sbr.x = -40;
		sbr.y = -1200; //sbr.y = -950;
		
		
		
		var rect = new createjs.Shape();
		rect.graphics.beginFill("#f00");
		rect.graphics.drawRect(0, 0, 1800, 1200); //rect.graphics.drawRect(0, 10, 1200, 920);
		rect.graphics.endFill();
		
		that.addChildAt(sbr, 0);
		
		sbr.hitArea = rect;
		
		
		
		
		sbr.addChild(that.shapeDraw);
		
		sbr.addChild(that.drect);
		sbr.addChild(that.drect0);
		
		sbr.addChild(that.dcir);
		sbr.addChild(that.dcir0);
		
		
		function makeCursor(px, py) {
		
		
			if (!sbr.contains(cursor)) {
		
				cursor = new createjs.Shape();
				cursor.graphics.beginFill("#ffffff");
				cursor.graphics.drawCircle(0, 0, that.somk * 2);
				cursor.cursor = "pointer";
		
		
				sbr.addChild(cursor);
			}
		
		
		
			cursor.x = px;
			cursor.y = py;
		
		
		
		}
		
		
		
		function drawSq(evt) {
		
		
			pt = sbr.globalToLocal(evt.stageX, evt.stageY);
		
		
			if (Math.abs(oldX - pt.x) > 6 || Math.abs(oldY - pt.y) > 6) {
		
				isMove = true;
		
			}
		
			that.drect.graphics.clear();
			//that.drect.updateCache("source-over");
		
			that.drect.graphics.beginFill("#525252");
			that.drect.graphics.drawRect(oldX, oldY, pt.x - oldX, pt.y - oldY);
			that.drect.graphics.endFill();
		
			stage.update();
		
		}
		function drawCi(evt) {
		
		
			pt = sbr.globalToLocal(evt.stageX, evt.stageY);
		
			if (Math.abs(oldX - pt.x) > 6 || Math.abs(oldY - pt.y) > 6) {
		
				isMove = true;
		
			}
		
			that.dcir.graphics.clear();
			//that.drect.updateCache("source-over");
		
			that.dcir.graphics.beginFill("#525252");
			that.dcir.graphics.drawCircle(oldX, oldY, Math.max(Math.abs(pt.x - oldX), Math.abs(pt.y - oldY)));
			that.dcir.graphics.endFill();
		
			stage.update();
		
		}
		
		function onpressmove(evt) {
		
		
		
			if (that.drawSquare) {
		
				drawSq(evt);
				return;
			}
		
		
			if (that.drawCircle) {
		
				drawCi(evt);
				return;
			}
		
		
			pt = sbr.globalToLocal(evt.stageX, evt.stageY);
		
			if (oldX) {
		
				that.shapeDraw.graphics.beginStroke(that.color)
		
				.setStrokeStyle(that.isErase ? that.somk * 3 : that.somk, "round")
		
				.moveTo(oldX, oldY)
		
				.lineTo(pt.x, pt.y);
		
		
		
				that.shapeDraw.updateCache(that.isErase ? "destination-out" : "source-over");
		
				that.shapeDraw.graphics.clear();
		
			}
		
			if (that.isErase) {
		
				makeCursor(pt.x, pt.y);
		
			}
		
			oldX = pt.x;
		
			oldY = pt.y;
		
			stage.update();
		
		}
		
		sbr.on("mouseout", function (evt) {
		
			isMove = false;
		
			sbr.removeEventListener("pressmove", onpressmove);
		
			sbr.removeChild(cursor);
		});
		
		
		sbr.on("click", function (evt) {
		
		
			if (isMove) return;
		
			var pt = sbr.globalToLocal(evt.stageX, evt.stageY);
			var ptcir0 = sbr.localToLocal(pt.x, pt.y, that.parent.getCont());
			var ol = sbr.localToLocal(oldX, oldY, that.parent.getCont());
		
		
		
			for (var r = 0; r < hjbArrays.length; r++) {
		
		
				if (Math.abs(hjbArrays[r].x - ol.x) < 10 && Math.abs(hjbArrays[r].y - ol.y) < 10) {
		
					// //alert("hjbArrays.length = "+hjbArrays.length +". r = "+r);
					that.parent.removeHjb(hjbArrays.length - 1 - r);
		
					hjbArrays.splice(r, 1);
				}
			}
		});
		
		
		
		//   pressup
		
		
		sbr.on("pressup", function (evt) {
		
		
			isMove = false;
		
			sbr.removeEventListener("pressmove", onpressmove);
		
			sbr.removeChild(cursor);
		
			if (that.drawSquare) {
		
		
				var pt = sbr.globalToLocal(evt.stageX, evt.stageY);
				var ptcir0 = sbr.localToLocal(pt.x, pt.y, that.parent.getCont());
				var ol = sbr.localToLocal(oldX, oldY, that.parent.getCont());
		
		
				that.drect.graphics.clear();
		
		
				//that.dcir0 = new createjs.Shape();
				var drect0 = new createjs.Shape();
		
		
		
				drect0.cache(-ol.x, -ol.y, 1800, 780);
		
				//that.parent.addChild(dcir0);
		
				drect0.graphics.beginFill("#525252");
				drect0.graphics.drawRect(0, 0, ptcir0.x - ol.x, ptcir0.y - ol.y);
				drect0.graphics.endFill();
		
				drect0.x = ol.x;
				drect0.y = ol.y;
		
				drect0.typeofShape = "square";
		
				drect0.updateCache("source-over");
		
				drect0.graphics.clear();
		
		
		
				drect0.width = ptcir0.x - ol.x;
				drect0.height = ptcir0.y - ol.y;
		
		
				if (Math.abs(drect0.width) > 15) {
		
					hjbArrays.push(drect0);
		
					addShape(drect0);
		
				}
		
			}
		
		
		
			if (that.drawCircle) {
		
		
				var pt = sbr.globalToLocal(evt.stageX, evt.stageY);
				var ptcir0 = sbr.localToLocal(pt.x, pt.y, that.parent.getCont());
				var ol = sbr.localToLocal(oldX, oldY, that.parent.getCont());
		
		
				that.dcir.graphics.clear();
		
		
				//that.dcir0 = new createjs.Shape();
				var dcir0 = new createjs.Shape();
		
		
		
				dcir0.cache(-ol.x, -ol.y, 1800, 780);
		
				//that.parent.addChild(dcir0);
		
				dcir0.graphics.beginFill("#525252");
				dcir0.graphics.drawCircle(0, 0, Math.max(Math.abs(ptcir0.x - ol.x), Math.abs(ptcir0.y - ol.y)));
				dcir0.graphics.endFill();
		
				dcir0.x = ol.x;
				dcir0.y = ol.y;
		
				dcir0.typeofShape = "circle";
		
				dcir0.updateCache("source-over");
		
				dcir0.graphics.clear();
		
		
		
				dcir0.width = Math.abs(ptcir0.x - ol.x);
				dcir0.height = Math.abs(ptcir0.y - ol.y);
		
				if (Math.abs(dcir0.width) > 15 || Math.abs(dcir0.height) > 15) {
		
					hjbArrays.push(dcir0);
		
					addShape(dcir0);
		
				}
		
			}
		
		
		});
		
		
		function addShape(shape) {
		
			that.parent.addShapeToKtb(shape);
		
		
		
		}
		
		
		sbr.on("mousedown", function (evt) {
		
			evt.nativeEvent.preventDefault();
		
			sbr.addEventListener("pressmove", onpressmove);
		
		
			pt = sbr.globalToLocal(evt.stageX, evt.stageY);
		
			oldX = pt.x;
		
			oldY = pt.y;
		
		
			if (!that.drawCircle && !that.drawSquare) {
		
				that.shapeDraw.graphics.beginStroke(that.color)
		
				.setStrokeStyle(that.somk, "round")
		
				.moveTo(oldX, oldY)
		
				.lineTo(oldX + 1, oldY + 1);
		
			}
		
			that.shapeDraw.updateCache(that.isErase ? "destination-out" : "source-over");
		
			that.shapeDraw.graphics.clear();
		
			stage.update();
		});
		
		
		function kom(eve) { //qalam
		
		
			if (eve !== null && !eve.nativeEvent instanceof MouseEvent){
				alert(eve);
				return;
			}
		alert('first is clicked');
		//eve.nativeEvent.preventDefault();
		eve.stopPropagation() ;
			that.isErase = false;
		
			that.qalam.bkg.alpha = 1;
			that.mimsaha.bkg.alpha = 0.6;
			that.circle.bkg.alpha = 0.6;
			that.square.bkg.alpha = 0.6;
		
			that.mimsaha.gotoAndStop(1);
		
			that.somkmc.gotoAndStop(that.currentsomk);
		
			that.drawCircle = false;
			that.drawSquare = false;
		
			that.setChildIndex(that.qalam, that.numChildren - 1);
		}
		
		that.kom = kom;
		function kom1(eve) { //mimsaha
		
			if (!eve.nativeEvent instanceof MouseEvent) {
				alert(eve);
				return;
			}
		eve.stopPropagation() ;
			that.isErase = true;
		
			that.drawCircle = false;
			that.drawSquare = false;
		
			eve.currentTarget.bkg.alpha = 1;
			that.qalam.bkg.alpha = 0.6;
			that.circle.bkg.alpha = 0.6;
			that.square.bkg.alpha = 0.6;
		
			that.qalam.gotoAndStop(that.currentcolor);
			that.somkmc.gotoAndStop(that.currentsomk);
		
			that.setChildIndex(eve.currentTarget, that.numChildren - 1);
		}
		
		
		
		function kom2(eve) { //somk
		
			if (!eve.nativeEvent instanceof MouseEvent) return;
		
			//that.drawCircle = false;
			//that.drawSquare = false;
		eve.stopPropagation() ;
			that.qalam.gotoAndStop(that.currentcolor);
			that.mimsaha.gotoAndStop(that.mimsaha.currentFrame < 3 ? that.mimsaha.currentFrame : 1);
		
			that.setChildIndex(eve.currentTarget, that.numChildren - 1);
		}
		
		function toSquare(eve) {
		
			if (!eve.nativeEvent instanceof MouseEvent) return;
		
		
			eve.currentTarget.bkg.alpha = 1;
			that.qalam.bkg.alpha = 0.6;
			that.mimsaha.bkg.alpha = 0.6;
			that.circle.bkg.alpha = 0.6;
		
		
			that.qalam.gotoAndStop(that.currentcolor);
			that.mimsaha.gotoAndStop(1);
			that.somkmc.gotoAndStop(that.currentsomk);
		
			that.drawSquare = !that.drawSquare;
		
		
			that.drawCircle = false;
		
			that.setChildIndex(eve.currentTarget, that.numChildren - 1);
		}
		
		function toCircle(eve) {
		
			if (!eve.nativeEvent instanceof MouseEvent) return;
		eve.stopPropagation() ;
			eve.currentTarget.bkg.alpha = 1;
			that.qalam.bkg.alpha = 0.6;
			that.mimsaha.bkg.alpha = 0.6;
			that.square.bkg.alpha = 0.6;
		
			that.qalam.gotoAndStop(that.currentcolor);
			that.mimsaha.gotoAndStop(1);
			that.somkmc.gotoAndStop(that.currentsomk);
		
			that.drawCircle = !that.drawCircle;
		
			that.drawSquare = false;
		
			that.setChildIndex(eve.currentTarget, that.numChildren - 1);
		}
		
		function kom3(eve) {
		
		
		
			eve.stopImmediatePropagation();
		eve.stopPropagation() ;
			if (eve.nativeEvent instanceof MouseEvent) {
		
		
		
				that.shapeDraw.graphics.clear();
				that.shapeDraw.updateCache();
		
				that.drect0.graphics.clear();
				that.drect0.updateCache();
		
				//that.dcir0.graphics.clear();
				//that.dcir0.updateCache();
		
				that.mimsaha.gotoAndStop(0);
				that.somkmc.gotoAndStop(that.currentsomk);
				that.qalam.gotoAndStop(that.currentcolor);
		
				that.isErase = false;
		
				that.drawCircle = false;
				that.drawSquare = false;
		
				hjbArrays.splice(0);
				sbr.removeAllChildren();
		
				clearListener();
		
				that.removeAllChildren();
		
				that.parent.unblockChafaf();
		
				that.gotoAndPlay(0);
		
			}
		}
		function clearListener() {
		
			sbr.removeAllEventListeners();
		
		
		
		}
	}

